arguments.argument:
if global.gamePaused=false
{
  if atkProg=0 //Go up
  {
    y-=6
    if y<=yAtk {atkProg=1}
  }
  else if atkProg=1 //Grow
  {
    image_yscale+=0.1
    if image_yscale>=1.7 {atkProg=2}
  }
  else if atkProg=2 //Fire
  {
    x+=moveSpd
    if image_xscale=1 and moveSpd<7 {moveSpd+=0.2}
    if image_xscale=-1 and moveSpd>-7 {moveSpd-=0.2}
  }
}
